public class Jsoup_parse_1_Test {

    @Test
    @DisplayName("parse(File, charsetName, baseUri) reads HTML file with explicit charset and baseUri")
    void test_TC07() throws IOException {
        // Bypass default BOM or null charset path: explicit charset triggers DataUtil.load(file, charset, baseUri)
        File file = File.createTempFile("tc07", ".html");
        file.deleteOnExit();
        String content = "<p>File</p>";
        Files.write(file.toPath(), content.getBytes("UTF-8"));
        String charset = "UTF-8";
        String baseUri = "http://file.example/";
        Document doc = Jsoup.parse(file, charset, baseUri);
        assertEquals("<p>File</p>", doc.body().html(), "Body HTML should match file content");
        assertEquals(baseUri, doc.baseUri(), "Base URI should be as provided");
    }

    @Test
    @DisplayName("parse(File, null charsetName) auto-detects charset and uses file path as baseUri")
    void test_TC08() throws IOException {
        // Null charset triggers BOM/meta detection path and baseUri defaults to file.getAbsolutePath()
        File file = File.createTempFile("tc08", ".html");
        file.deleteOnExit();
        String content = "<div>Auto</div>";
        Files.write(file.toPath(), content.getBytes());
        String charset = null;
        Document doc = Jsoup.parse(file, charset);
        assertEquals("<div>Auto</div>", doc.body().html(), "Body HTML should match file content");
        assertEquals(file.getAbsolutePath(), doc.baseUri(), "Base URI should default to file absolute path");
    }

    @Test
    @DisplayName("parse(File) calls DataUtil.load with null charset and file path as baseUri")
    void test_TC09() throws IOException {
        // Default overload: null charset, path -> DataUtil.load(File, null, path)
        File file = File.createTempFile("tc09", ".html");
        file.deleteOnExit();
        String content = "<span>X</span>";
        Files.write(file.toPath(), content.getBytes());
        Document doc = Jsoup.parse(file);
        assertEquals("<span>X</span>", doc.body().html(), "Body HTML should match file content");
        assertEquals(file.getAbsolutePath(), doc.baseUri(), "Base URI should default to file absolute path");
    }

    @Test
    @DisplayName("parse(File, charsetName, baseUri, Parser) uses custom Parser for file input")
    void test_TC10() throws IOException {
        // Custom parser stub path: DataUtil.load should call parser.parseInput internally
        File file = File.createTempFile("tc10", ".html");
        file.deleteOnExit();
        Files.write(file.toPath(), "irrelevant".getBytes());
        Parser stub = new Parser(null) {
            @Override public Document parseInput(String in, String base) {
                return new Document("stub-base").parser(stub);
            }
        };
        Document result = Jsoup.parse(file, "UTF-8", "base", stub);
        // The returned Document should have our stub set as parser
        assertSame(stub, result.parser(), "Parser of returned Document should be the stub");
    }

