        assertEquals("<em>C</em>", doc.body().html(), "Body HTML should match path content");
        assertEquals(path.toAbsolutePath().toString(), doc.baseUri(), "Base URI should default to path absolute string");
    }

    @Test
    @DisplayName("parse(Path) default overload with null charset uses path as baseUri")
    void test_TC13() throws IOException {
        // Default Path overload: null charset, baseUri defaults to path absolute
