        Files.write(path, "<div>D</div>".getBytes());
        Document doc = Jsoup.parse(path);
        assertEquals("<div>D</div>", doc.body().html(), "Body HTML should match path content");
        assertEquals(path.toAbsolutePath().toString(), doc.baseUri(), "Base URI should default to path absolute string");
    }

    @Test
    @DisplayName("parse(InputStream, charsetName, baseUri) reads from a stream")
    void test_TC14() throws IOException {
        // Stream overload: explicit charset and baseUri
        String html = "<h1>Stream</h1>";
        try (InputStream in = new ByteArrayInputStream(html.getBytes("UTF-8"))) {
            String charset = "UTF-8";
