            assertEquals("<h1>Stream</h1>", doc.body().html(), "Body HTML should match stream content");
            assertEquals(baseUri, doc.baseUri(), "Base URI should be as provided");
        }
    }

    @Test
    @DisplayName("parse(InputStream, charsetName, baseUri, Parser) uses stub parser for streams")
