                }
            };
            Document result = Jsoup.parse(in, null, "base", stub);
            assertSame(stub, result.parser(), "Parser of returned Document should be the stub");
        }
    }

    @Test
    @DisplayName("parse(URL, timeoutMillis) throws MalformedURLException on unsupported protocol")
    void test_TC16() {
        // URL with ftp scheme should trigger MalformedURLException in URL validation path
